mapper.select:
/* ProjectMainDao.getProjectName */
select
    odoc_nm
from t_odoc_main
where user_id = #{userId}
and odoc_sn = #{odocSn}

mapper.update:
/* ProjectMainDao.updateProject */
update t_odoc_main set

        end_yn = #{endYn}


        del_yn = #{delYn}


        odoc_nm = #{odocNm}

where user_id = #{userId}
and odoc_sn = #{odocSn}

mapper.insert:
/* ProjectMainDao.insertProject */
insert into t_odoc_main
(
    user_id
    , odoc_nm
    , frst_reg_dt
)
values
(
    #{userId}
    , #{odocNm}
    , (CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Seoul')
)

/* ProjectMainDao.commitProject */
insert into t_odoc_dtl
(
    odoc_sn
    , user_id
    , odoc_dt
    , frst_reg_dt
)
values
(
    #{odocSn}
    , #{userId}
    , (CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Seoul')
    , (CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Seoul')
)

mapper.select:
/* ProjectMainDao.getTempUser */
select
    is_motivation_alert
from t_user
where user_id = #{userId}

mapper.update:
/* ProjectMainDao.updateTempUser */
update t_user set
    is_motivation_alert = #{isMotivationAlert}
where user_id = #{userId}
